    const adj: Map<string, string[]> = new Map();
    const indegree: Map<string, number> = new Map();

    for (const task of tasks) {
        adj.set(task, []);
        indegree.set(task, 0);
    }

    for (let i = 0; i < M; i++) {
        const [a, b] = lines[2 + i].split(' ');
        adj.get(a)!.push(b);
        indegree.set(b, indegree.get(b)! + 1);
    }

